import { HttpErrorResponse } from "@angular/common/http";
import { Component, OnInit } from "@angular/core";
import { FormBuilder, FormGroup } from "@angular/forms";
import { AlertService } from "src/app/core/services/alert.service";
import { LoansService } from "src/app/core/services/loans.service";
import { ReferencesService } from "src/app/core/services/references.service";
import { IClientType } from "src/app/views/Models/Client/ClientType";
import { LoanTypeRef } from "src/app/views/Models/Loan/LoanType";
import { BranchModelResponse } from "src/app/views/Models/References/Branch";
import { Funders } from "src/app/views/Models/References/Funders";
import { StaticRef } from "src/app/views/Models/References/StaticRef";
import * as customValidators from "src/app/core/validators/custom-validators";
import { IscoreHttpService } from "src/app/core/services/iscore-http.service";
import {
  ExtractFileReportType,
  ExtractFileRequest,
} from "src/app/core/models/IScore/ExtractFile";

interface YearList {
  name: string;
  value: number;
}

@Component({
  selector: "app-extract-file",
  templateUrl: "./extract-file.page.html",
  styleUrls: ["./extract-file.page.scss"],
})
export class ExtractFilePage implements OnInit {
  constructor(
    private formBuilder: FormBuilder,
    private referencesService: ReferencesService,
    private alertService: AlertService,
    private loansService: LoansService,
    private iScoreService: IscoreHttpService
  ) {}

  showLoader: boolean = false;

  reportsTypesList: StaticRef[] = [];
  monthsList: StaticRef[] = [];
  yearsList: YearList[] = [];
  fundersList: Funders[] = [];
  clientTypesList: IClientType[] = [];
  branchesList: BranchModelResponse[] = [];
  loanTypeCategoriesList: StaticRef[] = [];
  loanTypesList: LoanTypeRef[] = [];

  ReportType = ExtractFileReportType;
  currentReportType: ExtractFileReportType = this.ReportType.Monthly;

  informationForm: FormGroup = this.formBuilder.group({
    loansStartDate: [
      new Date(1980, 0, 1),
      [customValidators.dateTypeStringValidator({ required: true })],
    ],
    reportType: [
      this.currentReportType,
      [customValidators.generalValidation({ required: true })],
    ],
    month: [
      new Date().getMonth().toString(),
      [customValidators.generalValidation({ required: true })],
    ],
    year: [
      new Date().getFullYear(),
      [customValidators.generalValidation({ required: true })],
    ],
    date: [new Date()],
    funders: [null, [customValidators.generalValidation({ required: true })]],
    clientTypes: [
      null,
      [customValidators.generalValidation({ required: true })],
    ],
    branches: [null, [customValidators.generalValidation({ required: true })]],
    loanTypeCategory: [
      null,
      [customValidators.generalValidation({ required: true })],
    ],
    loanTypes: [null, [customValidators.generalValidation({ required: true })]],
    fromActivityStart: [true],
  });

  get loanTypes() {
    const loanTypeCategories: string =
      this.informationForm.value.loanTypeCategory;
    if (!loanTypeCategories) return [];
    return this.loanTypesList.filter(
      (loan) => loan.loan_type_cat === Number(loanTypeCategories)
    );
  }

  async ngOnInit() {
    await this.fetchingData();
    this.yearsList = this.generateYearsList();
  }
  async fetchingData() {
    this.clientTypesList = await this.referencesService.GetClientTypes();
    this.branchesList = await this.referencesService.getAllBranches();
    this.loanTypeCategoriesList =
      await this.referencesService.getLoanTypeCategories();
    this.loanTypesList = await this.loansService.getLoanTypes();
    this.referencesService.getIScoreReportType().subscribe(
      (data) => (this.reportsTypesList = data),
      (error) => this.handleError(error)
    );
    this.referencesService.getMonths().subscribe(
      (data) => (this.monthsList = data),
      (error) => this.handleError(error)
    );
    this.referencesService.getAllFunderCodeInSystem().subscribe(
      (data) => (this.fundersList = data),
      (error) => this.handleError(error)
    );
  }
  generateYearsList(): YearList[] {
    const currentYear = new Date().getFullYear();
    const range = (start: number, stop: number, step: number) =>
      Array.from(
        { length: (stop - start) / step + 1 },
        (_, i) => start + i * step
      ).map((year) => ({
        name: year.toString(),
        value: year,
      }));

    return range(currentYear, 1900, -1);
  }
  reportsTypeChanging(event: any) {
    const value: string = event.detail.value;
    switch (value) {
      case this.ReportType.Monthly:
        this.currentReportType = this.ReportType.Monthly;
        this.informationForm.controls["month"].setValidators([
          customValidators.generalValidation({ required: true }),
        ]);
        this.informationForm.controls["month"].updateValueAndValidity();
        this.informationForm.controls["year"].setValidators([
          customValidators.generalValidation({ required: true }),
        ]);
        this.informationForm.controls["year"].updateValueAndValidity();
        this.informationForm.controls["date"].setValidators([]);
        this.informationForm.controls["date"].updateValueAndValidity();
        break;
      case this.ReportType.Daily:
        this.currentReportType = this.ReportType.Daily;
        this.informationForm.controls["month"].setValidators([]);
        this.informationForm.controls["month"].updateValueAndValidity();
        this.informationForm.controls["year"].setValidators([]);
        this.informationForm.controls["year"].updateValueAndValidity();
        this.informationForm.controls["date"].setValidators([
          customValidators.dateTypeStringValidator({ required: true }),
        ]);
        this.informationForm.controls["date"].updateValueAndValidity();
        break;
    }
  }
  loanTypeCategoryChanging(event: any) {
    const loanTypeCat: string = event.detail.value;
    this.informationForm.patchValue({
      loanTypes: null,
      loanTypeCategory: loanTypeCat,
    });
  }

  async extractFile() {
    try {
      const isValid = this.informationForm.valid;
      this.informationForm.markAllAsTouched();
      if (!isValid) return;
      this.showLoader = true;

      const request: ExtractFileRequest = {
        loansStartDate: this.informationForm.controls["loansStartDate"].value,
        reportType: this.currentReportType,
        extractMonth:
          this.currentReportType === this.ReportType.Monthly
            ? this.informationForm.controls["month"].value
            : null,
        extractYear:
          this.currentReportType === this.ReportType.Monthly
            ? this.informationForm.controls["year"].value
            : null,
        extractDate:
          this.currentReportType === this.ReportType.Daily
            ? this.informationForm.controls["date"].value
            : null,
        funders: this.informationForm.controls["funders"].value,
        clientTypes: this.informationForm.controls["clientTypes"].value,
        branches: this.informationForm.controls["branches"].value,
        loanTypeCategory:
          this.informationForm.controls["loanTypeCategory"].value,
        loanTypes: this.informationForm.controls["loanTypes"].value,
        fromActivityStart:
          this.informationForm.controls["fromActivityStart"].value,
      };

      console.log(request);
      const result = await this.iScoreService.extractFile(request).toPromise();
      if (!result.success)
        return this.alertService.showAlertError("خطأ في استخراج الملف", false);

      this.alertService.showAlertConfirm("لقد تم استخراج الملف", true);

    } catch (error) {
      this.handleError(error);
    } finally {
      this.showLoader = false;
    }
  }

  private handleError(error: unknown) {
    const errorMessage =
      error instanceof HttpErrorResponse
        ? JSON.stringify(error.error)
        : error instanceof Error
        ? error.message
        : String(error);

    this.alertService.showAlertError(errorMessage, false);
    console.error("Error:", error);
  }
}
